#define min( a, b )			( (a) > (b) ? (b) : (a) )
#define ceilDiv( a, b )		( (a) + (b) - 1 ) / (b)
#define print( x )			printf( #x ": %lu\n", (unsigned long) x )
#define DEBUG				false

#define DEFAULT_THREADS_PER_BLOCK 256

#define MAX_ARGS 10
#define REC_LENGTH 53 
#define LATITUDE_POS 28	
#define OPEN 10000	

#define MAX_RECORDS 1000000

typedef struct latLong
{
  float lat;
  float lng;
} LatLong;

typedef struct record
{
  char recString[REC_LENGTH];
  float distance;
} Record;

int loadData(char *filename, Record *records, LatLong *locations, int *numRecords);
void findLowest(Record *records, float *distances, int numRecords, int topN);
void printUsage();
int parseCommandline(int argc, char *argv[], char* filename, int *r, float *lat, float *lng,
                     int *q, int *t, int *p, int *d);

void euclid_openmp(LatLong *locations, float *distances, int numRecords, float lat, float lng)
{
    #pragma omp parallel for
    for (int globalId = 0; globalId < numRecords; ++globalId) {
        LatLong *latLong = &locations[globalId];
        float *dist = &distances[globalId];
        *dist = (float)sqrt((lat - latLong->lat)*(lat - latLong->lat) + (lng - latLong->lng)*(lng - latLong->lng));
    }
}

int main(int argc, char* argv[])
{
	int    i=0;
	float lat, lng;
	int quiet=0,timing=0,platform=0,device=0;

    static Record records[MAX_RECORDS];
    static LatLong locations[MAX_RECORDS];
    char filename[100];
    int resultsCount=10;
    int numRecords = 0;


    if (parseCommandline(argc, argv, filename,&resultsCount,&lat,&lng,
                     &quiet, &timing, &platform, &device)) {
      printUsage();
      return 0;
    }

    numRecords = loadData(filename, records, locations, &numRecords);
    if (numRecords < resultsCount) resultsCount = numRecords;






	float *distances;

	LatLong *d_locations;
	float *d_distances;

    // Simulating CUDA device property checks with OpenMP reasonable defaults
    unsigned long maxGridX = 65536; // Typical max grid size
    unsigned long threadsPerBlock = DEFAULT_THREADS_PER_BLOCK;

    // Memory check simulation (using system memory availability roughly)
    size_t totalDeviceMemory = 0;
    size_t freeDeviceMemory = 0;
    // In OpenMP, we rely on host memory, so we just check if numRecords is reasonable
    // For the sake of the original logic, we assume sufficient memory unless numRecords is huge
    unsigned long usableDeviceMemory = 1024 * 1024 * 1024; // Assume 1GB available for calculation
    unsigned long maxThreads = usableDeviceMemory / 12; 

    if ( maxThreads < (unsigned long)numRecords )
    {
        fprintf( stderr, "Error: Input too large.\n" );
        exit( 1 );
    }

    unsigned long blocks = ceilDiv( numRecords, threadsPerBlock ); 
    unsigned long gridY = ceilDiv( blocks, maxGridX );
    unsigned long gridX = ceilDiv( blocks, gridY );

    // In OpenMP, we don't strictly need grid dimensions, but we preserve the logic for debugging
    if ( DEBUG )
    {
        print( totalDeviceMemory ); 
        print( freeDeviceMemory );
        print( usableDeviceMemory );
        print( maxGridX ); 
        print( threadsPerBlock );
        print( maxThreads );
        print( blocks ); 
        print( gridY );
        print( gridX );
    }

    // Allocate host memory (OpenMP uses host memory directly)
    distances = (float *)malloc(sizeof(float) * numRecords);
    d_locations = (LatLong *)malloc(sizeof(LatLong) * numRecords);
    d_distances = (float *)malloc(sizeof(float) * numRecords);

    // Copy data to "device" (which is just host memory in OpenMP)
    memcpy(d_locations, locations, sizeof(LatLong) * numRecords);

#ifdef  TIMING
    gettimeofday(&tv_kernel_start, NULL);
#endif

    // Execute parallel kernel
    euclid_openmp(d_locations, d_distances, numRecords, lat, lng);

#ifdef  TIMING
    gettimeofday(&tv_kernel_end, NULL);
    tvsub(&tv_kernel_end, &tv_kernel_start, &tv);
    kernel_time += tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

    // Copy results back (memcpy since both are host memory)
    memcpy(distances, d_distances, sizeof(float)*numRecords);


    findLowest(records, distances, numRecords, resultsCount);


    if (!quiet)
    for(i=0;resultsCount > i;i++) {
      printf("%s --> Distance=%f\n",records[i].recString,records[i].distance);
    }
    free(distances);

    free(d_locations);
    free(d_distances);

#ifdef  TIMING
    printf("Exec: %f\n", kernel_time);
#endif
}

int loadData(char *filename, Record *records, LatLong *locations, int *numRecords) {
    FILE   *flist,*fp;
	int    i=0;
	char dbname[64];
	int recNum=0;

    flist = fopen(filename, "r");
    if (!flist) {
        fprintf(stderr, "error opening filelist\n");
        exit(0);
    }

    while(!feof(flist)) {
		if(fscanf(flist, "%s\n", dbname) != 1) {
            if (!feof(flist)) {
                fprintf(stderr, "error reading filelist\n");
                exit(0);
            }
            break;
        }
        fp = fopen(dbname, "r");
        if(!fp) {
            printf("error opening a db\n");
            exit(1);
        }

        while(!feof(fp)){
            Record record;
            LatLong latLong;
            // Initialize recString to avoid garbage
            memset(record.recString, 0, REC_LENGTH);

            if (fgets(record.recString, 49, fp) == NULL) break;

            // Handle newline or EOF
            if (feof(fp)) break;

            char substr[6];

            for(i=0;5 > i;i++) {
                int idx = i + 28;
                if (idx < 49 && record.recString[idx] != '\n' && record.recString[idx] != '\0')
                    substr[i] = record.recString[idx];
                else
                    substr[i] = '0';
            }
            substr[5] = '\0';
            latLong.lat = atof(substr);

            for(i=0;5 > i;i++) {
                int idx = i + 33;
                if (idx < 49 && record.recString[idx] != '\n' && record.recString[idx] != '\0')
                    substr[i] = record.recString[idx];
                else
                    substr[i] = '0';
            }
            substr[5] = '\0';
            latLong.lng = atof(substr);

            locations[recNum] = latLong;
            records[recNum] = record;
            recNum++;

            if (recNum >= MAX_RECORDS) {
                fprintf(stderr, "Maximum records limit reached.\n");
                break;
            }
        }
        fclose(fp);
    }
    fclose(flist);

    *numRecords = recNum;
    return recNum;
}

void findLowest(Record *records, float *distances, int numRecords, int topN){
  int i,j;
  float val;
  int minLoc;
  Record tempRec;
  float tempDist;

  for(i=0;topN > i;i++) {
    minLoc = i;
    for(j=i;numRecords > j;j++) {
      val = distances[j];
      if (distances[minLoc] > val) minLoc = j;
    }

    tempRec = records[i];
    records[i] = records[minLoc];
    records[minLoc] = tempRec;

    tempDist = distances[i];
    distances[i] = distances[minLoc];
    distances[minLoc] = tempDist;


    records[i].distance = distances[i];
  }
}

int parseCommandline(int argc, char *argv[], char* filename, int *r, float *lat, float *lng,
                     int *q, int *t, int *p, int *d){
    int i;
    if (2 > argc) return 1; 
    strncpy(filename,argv[1],100);
    char flag;

    for(i=1;argc > i;i++) {
      if ('-' == argv[i][0]) {
        flag = argv[i][1];
          switch (flag) {
            case 'r': 
              i++;
              if (i < argc) *r = atoi(argv[i]);
              break;
            case 'l': 
              if ('a' == argv[i][2]) {
                i++;
                if (i < argc) *lat = atof(argv[i]);
              }
              else {
                i++;
                if (i < argc) *lng = atof(argv[i]);
              }
              break;
            case 'h': 
              return 1;
            case 'q': 
              *q = 1;
              break;
            case 't': 
              *t = 1;
              break;
            case 'p': 
              i++;
              if (i < argc) *p = atoi(argv[i]);
              break;
            case 'd': 
              i++;
              if (i < argc) *d = atoi(argv[i]);
              break;
        }
      }
    }
    if ((0 <= *d && 0 > *p) || (0 <= *p && 0 > *d)) 
      return 1;
    return 0;
}

